const input = $input.first().json;
const msg = input.user_message || input.message || '';
const lang = input.language || (/[\u0600-\u06FF]/.test(msg) ? 'ar' : 'en');

// Simple keyword check
let agent = 'support';
let intent = 'GENERAL';
let matched = [];

// Arabic keywords
if (msg.includes('سعر') || msg.includes('بكام') || msg.includes('كام')) {
  agent = 'sales'; intent = 'SALES_PRICE'; matched.push('price_ar');
}
else if (msg.includes('مشكلة') || msg.includes('شكوى')) {
  agent = 'complaint'; intent = 'COMPLAINT'; matched.push('complaint_ar');
}
else if (msg.includes('ضمان')) {
  agent = 'warranty'; intent = 'WARRANTY'; matched.push('warranty_ar');
}
else if (msg.includes('توصيل') || msg.includes('شحن')) {
  agent = 'support'; intent = 'DELIVERY'; matched.push('delivery_ar');
}
// English keywords
else if (msg.toLowerCase().includes('price') || msg.toLowerCase().includes('cost')) {
  agent = 'sales'; intent = 'SALES_PRICE'; matched.push('price_en');
}
else if (msg.toLowerCase().includes('problem') || msg.toLowerCase().includes('complaint')) {
  agent = 'complaint'; intent = 'COMPLAINT'; matched.push('complaint_en');
}
else if (msg.toLowerCase().includes('warranty')) {
  agent = 'warranty'; intent = 'WARRANTY'; matched.push('warranty_en');
}
else if (msg.toLowerCase().includes('delivery') || msg.toLowerCase().includes('shipping')) {
  agent = 'support'; intent = 'DELIVERY'; matched.push('delivery_en');
}

// Responses
const responses = {
  sales: { ar: 'تمام! أسعارنا بتبدأ من 12,500 جنيه', en: 'Our prices start from 12,500 EGP' },
  complaint: { ar: 'معلش جداً! ممكن تقولي إيه اللي حصل؟', en: 'I am sorry! Can you tell me what happened?' },
  warranty: { ar: 'ضمان يانسن 10 سنين', en: 'Janssen warranty is 10 years' },
  support: { ar: 'أهلاً! إزاي أقدر أساعدك؟', en: 'Hello! How can I help?' }
};

const text = responses[agent]?.[lang] || responses.support[lang];

return {
  json: {
    response: text,
    agent: agent,
    intent: intent,
    matched: matched,
    debug: {
      received_message: msg,
      detected_language: lang,
      raw_input: input
    }
  }
};
